-- Nibbles Bakery — realistic operating dataset (real rows). Re-runnable.
begin;
delete from transaction_lines where transaction_id in (select id from transactions where receipt_number like 'NBD-%');
delete from transactions where receipt_number like 'NBD-%';
delete from shifts where notes = 'std-week';
delete from customers where email like '%@nibblesmail.co.za';
update products set unit_price=16.00, sku='NB-BRD-WHT' where id='1cfe344a-48ee-4eda-bef0-51f3d4d85314';
update products set unit_price=22.00, sku='NB-CAKE-CUS', name='Custard Slice' where id='96bbfda4-2c5c-4d93-ac91-8ce8bb3860b1';
on conflict (id) do nothing;
on conflict (branch_id,product_id) do update set quantity_on_hand=excluded.quantity_on_hand, reorder_threshold=excluded.reorder_threshold, updated_at=now();
update customers c set
  total_spend = s.spend, total_visits = s.visits,
  loyalty_points = floor(s.spend/10)::int, last_visit_at = s.last
from (select customer_id, sum(total_amount) spend, count(*) visits, max(created_at) last
      from transactions where customer_id is not null and status='completed' group by customer_id) s
where c.id = s.customer_id;
on conflict (staff_id,shift_date,planned_start) do nothing;
commit;